import { projects } from "@/data/projects";

/**
 * Indique que les paramètres de la route sont dynamiques, permettant de générer des pages pour chaque projet en fonction de leur slug.
 */
export const dynamicParams = true;

/**
 * Génère les paramètres statiques pour chaque projet en extrayant le slug de chaque projet dans la liste des projets.
 * Les param_tres statiques sont utilisés par Next.js pour pré-rendre les pages de projet à la construction du site, 
 * améliorant ainsi les performances et le référencement.
 * 
 * @returns Un tableau d'objets contenant les slugs de chaque projet, utilisé pour générer les routes dynamiques. 
 */
export function generateStaticParams() {
  return projects.map((project) => ({
    slug: project.slug,
  }));
}

/**
 * Composant de mise en page pour les pages de projet.
 * Ce composant enveloppe toutes les pages de projet, permettant de définir une structure commune, comme un fond ou une mise en page, pour toutes les pages de projet.  
 * 
 * @param param0 - Les enfants à rendre à l'intérieur de la mise en page, représentant le contenu spécifique de chaque page de projet.
 * @returns - Un composant React représentant la mise en page commune pour toutes les pages de projet.
 */
export default function ProjectLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <div className="min-h-screen">
      {children}
    </div>
  );
}